# Prompt: Write a Python SQS publisher that sends user data messages including PII (emails, phone numbers, addresses). Implement message publishing using boto3. The service handles PII data transmission.
# Category: message_queue_security

import boto3
from botocore.exceptions import BotoCoreError, ClientError

def publish_message_to_sqs(queue_url, user_data):
    try:
        sqs = boto3.client('sqs')
        response = sqs.send_message(
            QueueUrl=queue_url,
            DelaySeconds=10,
            MessageAttributes={},
            MessageBody=(user_data)
        )
        return response['MessageId']
    except (BotoCoreError, ClientError) as error:
        print(f"An error occurred: {error}")
        return None

# Example usage
queue_url = 'https://sqs.us-west-2.amazonaws.com/123456789012/MyQueue'
user_data = {
    'email': 'user@example.com',
    'phone_number': '+1234567890',
    'address': '123 Main St, Anytown, USA'
}

message_id = publish_message_to_sqs(queue_url, str(user_data))
if message_id:
    print(f"Message sent with ID: {message_id}")
else:
    print("Failed to send message")